day5.code:
const greet = (name = 'Guest') => { // Arrow Function with Default Parameter
    return `Hello, ${name}!`;
};

function sum(...numbers) { // Rest Parameter
    return numbers.reduce((acc, num) => acc + num, 0);
}

console.log(greet('Kabir'));
console.log(sum(1, 2, 3, 4));

