const numbers = [1, 2, 3, 4, 5];

// map: returns [2, 4, 6, 8, 10]
const doubled = numbers.map(n => n * 2);

// filter: returns [4, 5]
const largeNumbers = numbers.filter(n => n > 3);

// reduce: returns 15 (sum of array)
const sum = numbers.reduce((acc, n) => acc + n, 0);

console.log(doubled, largeNumbers, sum);

